create table dirkspzm32.meldung_statistik (
    sid                  varchar2(2 char) not null enable,
    firma_nr             number(6, 0) not null enable,
    engine_id            number(*, 0),
    gruppe               number(3, 0) not null enable,
    bereich              varchar2(30 char) not null enable,
    ms_begin             date not null enable,
    ms_ende              date,
    ms_texte             varchar2(4000 char),
    ms_minuten           number(*, 12),
    ms_count             number(*, 0),
    created_date         date default sysdate not null enable,
    created_login_id     number(*, 0) default - 1 not null enable,
    last_change_date     date,
    last_change_login_id number(*, 0)
);


